import requests

def test_consent_invalid_payload_rejected(base_url, patient_token):
    headers = {'Authorization': f'Bearer {patient_token}'}
    invalid_payload = {
        'patient_id': 'P22222',
        'data_type': 'genomics'
    }
    resp = requests.post(f'{base_url}/Consent', json=invalid_payload, headers=headers)
    assert resp.status_code == 400
    error_data = resp.json()
    assert 'error' in error_data
    error_msg = error_data['error'].lower()
    assert 'granted' in error_msg or 'required' in error_msg

import requests

def test_consent_unauthorized_user_denied(base_url):
    payload = {
        'patient_id': 'P33333',
        'data_type': 'labs',
        'granted': True
    }
    resp = requests.post(f'{base_url}/Consent', json=payload)
    assert resp.status_code == 401
    assert 'unauthorized' in resp.json().get('error', '').lower() or 'authentication' in resp.json().get('error', '').lower()
